526	export function TicketCardContent({
527	  ticket,
528	  allTickets,
529	  columns,
530	  now
531	}: {
532	  ticket: TicketSummary;
533	  allTickets: TicketSummary[];
534	  columns: RelayColumn[];
535	  now: number;
536	}): ReactElement {
537	  const visibleLabels = ticket.labels.slice(0, 2);
538	  const hiddenLabelCount = ticket.labels.length - visibleLabels.length;
539	  const showPriority = ticket.priority === "high" || ticket.priority === "urgent";
540	  const showRunStatus = ticket.runStatus !== "idle";
541	  const elapsedLabel = activeRunElapsedLabel(ticket, now);
542	  const showRelationship = ticket.ticketType === "epic" || Boolean(ticket.parentEpicId);
543	  const blockerState = useMemo(() => resolveTicketBlockers(ticket, allTickets, columns), [allTickets, columns, ticket]);
544	  const showBlockerState = blockerState.isBlocked || blockerState.warnings.length > 0;
545	
546	  return (
547	    <>
548	      <div className="card-title">{ticket.title}</div>
549	      <p className="card-excerpt">{ticket.excerpt || "No details yet."}</p>
550	      {(showRelationship || showPriority || showRunStatus || showBlockerState || elapsedLabel) && (
551	        <div className="card-meta">
552	          {ticket.ticketType === "epic" && <span className="ticket-type-pill epic">Epic</span>}
553	          {ticket.parentEpicId && <span className="ticket-type-pill subticket">Subticket</span>}
554	          {blockerState.isBlocked && (
555	            <span className="ticket-blocker-pill active" title={blockerState.activeBlockers.map(resolvedBlockerLabel).join("; ")}>
556	              Blocked
557	            </span>
558	          )}
559	          {blockerState.warnings.length > 0 && (
560	            <span className="ticket-blocker-pill warning" title={blockerState.warnings.join(" ")}>
561	              Blocker Warning
562	            </span>
563	          )}
564	          {showPriority && <span className={clsx("priority", ticket.priority)}>{ticket.priority}</span>}
565	          {showRunStatus && <TicketRunStatusPill status={ticket.runStatus} />}
566	          {elapsedLabel && <TicketRunElapsedPill label={elapsedLabel} />}
567	        </div>
568	      )}
569	      {visibleLabels.length > 0 && (
570	        <div className="labels">
571	          {visibleLabels.map((label) => (
572	            <span key={label}>{label}</span>
573	          ))}
574	          {hiddenLabelCount > 0 && <span className="label-overflow">+{hiddenLabelCount}</span>}
575	        </div>
576	      )}
577	    </>
578	  );
